        "content"  : "\n<table class=\"infobox\" style=\"float:right;\">\n    <tr>\n        <th colspan=\"2\" style=\"font-size:22px;\">\n            \n                Fresh Blood Bag\n            \n            <br />\n            <span style=\"font-size:16px;\">(250ml | 500ml)</span>\n            \n        </th>\n    </tr>\n    <tr>\n        <td colspan=\"2\">\n            \n            <img src=\"/ACM-wiki/wiki/image/fbtk_full.png\" height=\"150\" />\n            \n        </td>\n    </tr>\n    <tr class=\"infobox-header\">\n        <td colspan=\"2\">Item</td>\n    </tr>\n    <tr>\n        <td colspan=\"2\" style=\"padding:0;\">\n            <table class=\"infobox-inline-table\">\n                \n                <tr class=\"infobox-row\">\n                    <td class=\"infobox-row-title-itable-f\">Type</td>\n                    <td class=\"infobox-row-itable-f\" style=\"padding:5px 0 5px 0;\">Fluid Bag</td>\n                </tr>\n                \n                <tr class=\"infobox-row\">\n                    <td class=\"infobox-row-title-itable\">Category</td>\n                    <td class=\"infobox-row-itable\" style=\"padding:5px 0 5px 0;\">\n                        \n    <img src=\"/ACM-wiki/wiki/image/category_transfusion.png\" height=\"32\" /><span style=\"margin-left:4px;\">Transfusion</span>\n    \n\n                    </td>\n                </tr>\n                <tr class=\"infobox-row\">\n                    <td class=\"infobox-row-title-itable\">Action Access</td>\n                    <td class=\"infobox-row-itable\">\n                        \n<div class=\"infobox-selection-img\"><img src=\"/ACM-wiki/assets/images/infobox/body_select_torso_limbs.png\" height=\"64\" /></div><div class=\"infobox-selection-text\">Torso<br />Arms<br />Legs</div>\n\n                    </td>\n                </tr>\n                <tr class=\"infobox-row\">\n                    <td class=\"infobox-row-title-itable\">Use Count</td>\n                    <td class=\"infobox-row-itable\">\n                        \n    Single-use\n\n                    </td>\n                </tr>\n                <tr class=\"infobox-row\">\n                    <td class=\"infobox-row-title-itable\">Weight</td>\n                    <td class=\"infobox-row-itable\">\n                        \n\n    0.11kg | 0.25lb<br />\n\n    0.23kg | 0.5lb<br />\n\n\n                    </td>\n                </tr>\n            </table>\n        </td>\n    </tr>\n    \n    \n    <tr class=\"infobox-header\">\n        <td colspan=\"2\">Technical</td>\n    </tr>\n    <tr>\n        <td colspan=\"2\" style=\"padding:0;\">\n            <table class=\"infobox-inline-table\">\n                <tr class=\"infobox-row\">\n                    \n                    <td class=\"infobox-row-title-itable-f\">Classname</td>\n                    <td class=\"infobox-row-itable-f\">N/A</td>\n                    \n                </tr>\n            </table>\n        </td>\n    </tr>\n</table>\n"
     
